function normalizeText(value){return clean(value).toLowerCase().replace(/[\p{P}\p{S}]/gu,"").replace(/\d{4}$/,"").trim()}
function dateISO(value){const raw=clean(value);if(!raw||/^\d{4}$/.test(raw))return null;const match=raw.match(/^(\d{4})[년.\/-]\s*(\d{1,2})[월.\/-]\s*(\d{1,2})(?:일)?$/);if(!match)return null;const y=Number(match[1]),m=Number(match[2]),d=Number(match[3]),date=new Date(Date.UTC(y,m-1,d));return date.getUTCFullYear()===y&&date.getUTCMonth()===m-1&&date.getUTCDate()===d?`${y}-${String(m).padStart(2,"0")}-${String(d).padStart(2,"0")}`:null}
